package com.google.gson;
import com.google.gson.internal.NonNullElementWrapperList;
import java.math.BigDecimal;
import java.math.BigInteger;
import java.util.Iterator;
import java.util.List;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;
import java.util.ArrayList;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class JsonArrayTest {

  private JsonArray jsonArray;
  private JsonElement mockElement;

  @BeforeEach
  public void setUp() {
    jsonArray = new JsonArray();
    mockElement = mock(JsonElement.class);
  }

  @Test
  public void testGetAsNumber_withSingleElement_returnsNumber() {
    // Arrange
    when(mockElement.getAsNumber()).thenReturn(42);
    jsonArray.add(mockElement);

    // Act
    Number result = jsonArray.getAsNumber();

    // Assert
    assertEquals(42, result);
    verify(mockElement).getAsNumber();
  }

  @Test
  public void testGetAsNumber_withMultipleElements_invokesFirstElement() {
    // Arrange
    JsonElement first = mock(JsonElement.class);
    JsonElement second = mock(JsonElement.class);
    when(first.getAsNumber()).thenReturn(10);
    jsonArray.add(first);
    jsonArray.add(second);

    // Act
    Number result = jsonArray.getAsNumber();

    // Assert
    assertEquals(10, result);
    verify(first).getAsNumber();
    verifyNoMoreInteractions(second);
  }

  @Test
  public void testGetAsNumber_emptyArray_throwsIndexOutOfBoundsException() throws Exception {
    // Arrange
    // Use reflection to invoke private method getAsSingleElement to confirm behavior
    Method getAsSingleElement = JsonArray.class.getDeclaredMethod("getAsSingleElement");
    getAsSingleElement.setAccessible(true);

    // Act & Assert
    IndexOutOfBoundsException thrown = assertThrows(IndexOutOfBoundsException.class, () -> {
      getAsSingleElement.invoke(jsonArray);
    });
    assertNotNull(thrown);
  }

  @Test
  public void testGetAsSingleElement_reflection_singleElement() throws Exception {
    // Arrange
    jsonArray.add(mockElement);
    Method getAsSingleElement = JsonArray.class.getDeclaredMethod("getAsSingleElement");
    getAsSingleElement.setAccessible(true);

    // Act
    JsonElement result = (JsonElement) getAsSingleElement.invoke(jsonArray);

    // Assert
    assertSame(mockElement, result);
  }

  @Test
  public void testGetAsNumber_withNullElement_throwsNullPointerException() {
    // Arrange
    jsonArray.add(null);

    // Act & Assert
    assertThrows(NullPointerException.class, () -> jsonArray.getAsNumber());
  }
}
